var device = new CDeviceMCRCognex();
// DLL 버전 정보 읽기
string version = comm.HLGetVersion();
Console.WriteLine($"DLL 버전: {version}");
return;

var mcrError = new CDeviceMCRCognexDefine.CMCRError();
// DLL 버전 정보 읽기
var error = mcrError.HLGetErrorCode();
Console.WriteLine($"이벤트 발생 시간: {error.strEventTime}");
Console.WriteLine($"수행된 함수 이름: {error.strFunctionName}");
Console.WriteLine($"알람 리턴 결과: {error.iReturnCode}");
Console.WriteLine($"알람 메세지: {error.strMessage}");
return;

// 초기화 파라미터 설정
var initializeParameter = new CDeviceMCRCognexDefine.CInitializeParameter()
{
     strIPAddress = 192.168.0.63
     strPortNumber = 21;
};

// 라이브러리 초기화
var device = new CDeviceMCRCognex();
if (device.Initialize(initializeParameter) == false)
{
    // 초기화 실패
    return;
}

// 라이브러리 정리
device.DeInitialize();
return;

// 초기화 파라미터 설정
var initializeParameter = new CDeviceMCRCognexDefine.CInitializeParameter()
{
     strIPAddress = 192.168.0.63
     strPortNumber = 21;
};

// 라이브러리 초기화
var device = new CDeviceMCRCognex();
if (device.Initialize(initializeParameter) == false)
{
    // 초기화 실패
    return;
}

// 통신 준비 상태 확인
bool bIsConnected = device.HLIsConnected();
Console.WriteLine($"통신 준비 상태: {bIsConnected}");

// 라이브러리 정리
device.DeInitialize();
return;

// 초기화 파라미터 설정
var initializeParameter = new CDeviceMCRCognexDefine.CInitializeParameter()
{
     strIPAddress = 192.168.0.63
     strPortNumber = 21;
};

// 라이브러리 초기화
var device = new CDeviceMCRCognex();
if (device.Initialize(initializeParameter) == false)
{
    // 초기화 실패
    return;
}

// MCR 데이터 읽기
string strData = "";
if (device.HLReadData(ref strData) == true)
{
    Console.WriteLine($"MCR 리딩 데이터: {strData}");
}

// 라이브러리 정리
device.DeInitialize();
return;

// 초기화 파라미터 설정
