{
     strIPAddress = 192.168.0.63
     strPortNumber = 21;
};

// 라이브러리 초기화
var device = new CDeviceMCRCognex();
if (device.Initialize(initializeParameter) == false)
{
    // 초기화 실패
    return;
}

// 트리거 데이터 전송
device.HLTrigger();

// MCR 데이터 읽기
string strData = "";
if (device.HLReadData(ref strData) == true)
{
    Console.WriteLine($"MCR 리딩 데이터: {strData}");
}

// 라이브러리 정리
device.DeInitialize();
return;

