{
     strIPAddress = 192.168.0.63
     strPortNumber = 21;
};

// 라이브러리 초기화
var device = new CDeviceMCRCognex();
if (device.Initialize(initializeParameter) == false)
{
    // 초기화 실패
    return;
}

// 디바이스 네임 요청 데이터 전송
device.HLDeviceName();

// MCR 데이터 읽기
string strData = "";
if (device.HLReadData(ref strData) == true)
{
    Console.WriteLine($"MCR 리딩 데이터: {strData}");
}

// 라이브러리 정리
device.DeInitialize();
return;

// 초기화 파라미터 설정
var initializeParameter = new CDeviceMCRCognexDefine.CInitializeParameter()
{
     strIPAddress = 192.168.0.63
     strPortNumber = 21;
};

// 라이브러리 초기화
var device = new CDeviceMCRCognex();
if (device.Initialize(initializeParameter) == false)
{
    // 초기화 실패
    return;
}

// 시리얼 넘버 요청 데이터 전송
device.HLSerialNo();

// MCR 데이터 읽기
string strData = "";
if (device.HLReadData(ref strData) == true)
{
    Console.WriteLine($"MCR 리딩 데이터: {strData}");
}

// 라이브러리 정리
device.DeInitialize();
